// Reads directly from previous node (no node name needed)
const competitorName = $json.competitor_name;
const pageId = $json.facebook_page_id;
const niche = $json.niche;

// Mock ad snapshot data
const mockAds = [
  {
    ad_id: `AD-${Math.floor(Math.random() * 9000) + 1000}`,
    headline: `Best ${niche} products - Limited offer!`,
    cta: 'Shop Now',
    format: 'Image',
    estimated_reach: Math.floor(Math.random() * 50000) + 10000,
    run_days: Math.floor(Math.random() * 30) + 1,
    spend_estimate: `$${Math.floor(Math.random() * 5000) + 500}`
  },
  {
    ad_id: `AD-${Math.floor(Math.random() * 9000) + 1000}`,
    headline: `${competitorName} - New Collection 2026`,
    cta: 'Learn More',
    format: 'Video',
    estimated_reach: Math.floor(Math.random() * 80000) + 20000,
    run_days: Math.floor(Math.random() * 20) + 5,
    spend_estimate: `$${Math.floor(Math.random() * 8000) + 1000}`
  },
  {
    ad_id: `AD-${Math.floor(Math.random() * 9000) + 1000}`,
    headline: `Why ${competitorName} leads the market`,
    cta: 'Sign Up',
    format: 'Carousel',
    estimated_reach: Math.floor(Math.random() * 30000) + 5000,
    run_days: Math.floor(Math.random() * 15) + 2,
    spend_estimate: `$${Math.floor(Math.random() * 3000) + 200}`
  }
];

// Pattern analysis
const formats = mockAds.map(a => a.format);
const topFormat = formats.sort((a, b) =>
  formats.filter(v => v === b).length - formats.filter(v => v === a).length
)[0];

const avgReach = Math.floor(
  mockAds.reduce((sum, a) => sum + a.estimated_reach, 0) / mockAds.length
);

const topAd = mockAds.reduce((prev, current) =>
  prev.estimated_reach > current.estimated_reach ? prev : current
);

return {
  json: {
    competitor_name: competitorName,
    page_id: pageId,
    niche: niche,
    total_ads: mockAds.length,
    top_format: topFormat,
    avg_reach: avgReach,
    top_ad_headline: topAd.headline,
    top_ad_reach: topAd.estimated_reach,
    top_ad_spend: topAd.spend_estimate,
    ads_data: mockAds,
    run_date: new Date().toISOString().split('T')[0],
    status: 'success'
  }
};
